	if _, err := os.Stat(wrapper); err != nil {
		t.Fatalf("docker-wrapper.sh: %v", err)
	}
	cmd := exec.Command("bash", wrapper, "run", "--rm", "ghcr.io/github/gh-aw-firewall/agent:9")
