		"GH_SR_DOCKER_WRAPPER_REAL=/bin/echo",
		"GH_SR_AWF_BRIDGE_GATEWAY_IP=10.20.30.40",
	)
	out, err := cmd.CombinedOutput()
	if err != nil {
		t.Fatalf("bash wrapper: %v\n%s", err, out)
	}
